   329					}
   330					level--
   331				}
   332			case xml.EndTagToken:
   333				if t.Hash == tag {
   334					if level == 0 {
   335						return
   336					}
   337					level--
   338				}
   339			}
   340			w.Write(t.Data)
   341			tb.Shift()
   342		}
   343	}
